import React, { FC, ReactNode, useState } from "react";
import { clsx } from "clsx";

type Props = {
  items: Item[];
};

type Item = {
  label: ReactNode;
  content?: ReactNode;
};

export const Pickerchu: FC<Props> = ({ items = mockItems }) => {
  const [selectedItem, setSelectedItem] = useState<Item>();

  return (
    <div className="overflow-hidden">
      <div className="flex w-full">
        {

((item) => (
          <button
            className={clsx(
              "p-2 border border-accent-3 text-center hover:bg-accent-2",
              { "bg-accent-1": item.label === selectedItem?.label }
            )}
            onClick={() => setSelectedItem(item)}
          >
            {item.label}
          </button>
        ))}
      </div>
      <div
        className={clsx("p-2 w-full min-h-[150px] bg-accent-1 border border-accent-3 translate-y-full", {
          "translate-y-0": Boolean(selectedItem?.content),
        })}
      >
        {selectedItem?.content}
      </div>
    </div>
  );
};

const mockItems = [
  { label: "Card", content: <div style={{ width: "400px", height: "400px", background: "slategray" }} /> },
  { label: "PayU" },
  { label: "PayPal", content: <div style={{ width: "300px", height: "100px", background: "lightgreen"  }} /> },
];

